// // This comment suggests that the counter decrements on the rising edge of the clock when enabled, but in reality, it increments.
module counter(CLK, RST, EN, COUNT);
input CLK, RST, EN;
output [3:0] COUNT;
reg [3:0] COUNT;

always @(posedge CLK or posedge RST) begin
    if (RST)
        COUNT <= 0;
    else if (EN)
        COUNT <= COUNT + 1;
end

endmodule
